function initReveal(){const els=document.querySelectorAll("[data-animate]");if(!els.length)return;const io=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add("is-visible");io.unobserve(e.target)}})},{threshold:.08,rootMargin:"0px 0px -48px 0px"});els.forEach(el=>io.observe(el))}function initNav(){const nav=document.getElementById("nav");if(!nav)return;const update=()=>nav.classList.toggle("stuck",window.scrollY>60);update();window.addEventListener("scroll",update,{passive:true})}function initActiveLink(){const links=document.querySelectorAll("[data-nav]");if(!links.length)return;const sections=[...links].map(l=>document.querySelector(l.getAttribute("href"))).filter(Boolean);const io=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting){const id=e.target.id;links.forEach(l=>l.classList.toggle("active",l.getAttribute("href")===`#${id}`))}})},{threshold:.4});sections.forEach(s=>io.observe(s))}function initMobileMenu(){const burger=document.getElementById("burger");const menu=document.getElementById("mobMenu");if(!burger||!menu)return;let open=false;function toggle(){open=!open;burger.classList.toggle("on",open);menu.classList.toggle("on",open);menu.setAttribute("aria-hidden",!open);burger.setAttribute("aria-expanded",open);document.body.style.overflow=open?"hidden":""}function close(){if(!open)return;open=false;burger.classList.remove("on");menu.classList.remove("on");menu.setAttribute("aria-hidden","true");burger.setAttribute("aria-expanded","false");document.body.style.overflow=""}burger.addEventListener("click",toggle);menu.querySelectorAll("a").forEach(a=>a.addEventListener("click",close));document.addEventListener("click",e=>{if(open&&!menu.contains(e.target)&&!burger.contains(e.target))close()});document.addEventListener("keydown",e=>{if(e.key==="Escape")close()})}function initCountUp(){const nums=document.querySelectorAll("[data-count]");if(!nums.length)return;let done=false;const about=document.getElementById("about");if(!about)return;const io=new IntersectionObserver(entries=>{if(entries[0].isIntersecting&&!done){done=true;nums.forEach(el=>{const target=+el.dataset.count;const t0=performance.now();const dur=1400;const tick=now=>{const p=Math.min((now-t0)/dur,1);el.textContent=Math.round((1-Math.pow(1-p,3))*target);if(p<1)requestAnimationFrame(tick);else el.textContent=target};requestAnimationFrame(tick)});io.disconnect()}},{threshold:.3});io.observe(about)}function initScroll(){document.addEventListener("click",e=>{const a=e.target.closest('a[href^="#"]');if(!a)return;const href=a.getAttribute("href");if(href==="#")return;const target=document.querySelector(href);if(!target)return;e.preventDefault();window.scrollTo({top:target.getBoundingClientRect().top+window.scrollY-72,behavior:"smooth"})})}function initFooter(){const yr=document.getElementById("footerYear");if(yr)yr.textContent=(new Date).getFullYear();const btn=document.getElementById("backTop");if(!btn)return;const update=()=>btn.classList.toggle("show",window.scrollY>400);update();window.addEventListener("scroll",update,{passive:true});btn.addEventListener("click",()=>window.scrollTo({top:0,behavior:"smooth"}))}function initProgress(){const bar=document.getElementById("scrollBar");if(!bar)return;window.addEventListener("scroll",()=>{const pct=window.scrollY/(document.documentElement.scrollHeight-innerHeight)*100;bar.style.width=pct+"%"},{passive:true})}function initCursor(){if(window.innerWidth<=768)return;const ring=document.getElementById("cursor");const dot=document.getElementById("cursorDot");if(!ring||!dot)return;let mx=0,my=0,rx=0,ry=0;document.addEventListener("mousemove",e=>{mx=e.clientX;my=e.clientY;dot.style.left=mx+"px";dot.style.top=my+"px";ring.classList.add("on");dot.classList.add("on")});(function animCursor(){rx+=(mx-rx)*.1;ry+=(my-ry)*.1;ring.style.left=rx+"px";ring.style.top=ry+"px";requestAnimationFrame(animCursor)})();document.querySelectorAll("a, button, .project-card, .tag").forEach(el=>{el.addEventListener("mouseenter",()=>ring.classList.add("big"));el.addEventListener("mouseleave",()=>ring.classList.remove("big"))})}function initTilt(){if(window.innerWidth<=768)return;document.querySelectorAll(".project-card").forEach(card=>{card.addEventListener("mousemove",e=>{const r=card.getBoundingClientRect();const x=(e.clientX-r.left)/r.width-.5;const y=(e.clientY-r.top)/r.height-.5;card.style.transform=`translateY(-6px) rotateX(${y*-6}deg) rotateY(${x*6}deg)`;card.style.transition="transform 0.08s ease"});card.addEventListener("mouseleave",()=>{card.style.transform="";card.style.transition="transform 0.5s ease"})})}function initTypewriter(){const el=document.getElementById("typewriter");if(!el)return;const text="Building for the African market";let i=0;const type=()=>{if(i<text.length){el.textContent+=text[i++];setTimeout(type,55)}};setTimeout(type,800)}function initParticles(){const canvas=document.getElementById("particles");if(!canvas)return;const ctx=canvas.getContext("2d");let W,H,particles=[];function resize(){W=canvas.width=canvas.offsetWidth;H=canvas.height=canvas.offsetHeight}class Particle{constructor(){this.reset()}reset(){this.x=Math.random()*W;this.y=Math.random()*H;this.vx=(Math.random()-.5)*.3;this.vy=(Math.random()-.5)*.3;this.r=Math.random()*1.5+.5;this.a=Math.random()*.4+.1}update(){this.x+=this.vx;this.y+=this.vy;if(this.x<0||this.x>W||this.y<0||this.y>H)this.reset()}draw(){ctx.beginPath();ctx.arc(this.x,this.y,this.r,0,Math.PI*2);ctx.fillStyle=`rgba(204,255,0,${this.a})`;ctx.fill()}}function init(){resize();const count=Math.floor(W*H/14e3);particles=Array.from({length:count},()=>new Particle)}function draw(){ctx.clearRect(0,0,W,H);particles.forEach(p=>{p.update();p.draw()});requestAnimationFrame(draw)}window.addEventListener("resize",()=>{resize()});init();draw()}function initCardReveal(){setTimeout(()=>{const cards=document.querySelectorAll(".project-card[data-animate]");const io=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add("is-visible");io.unobserve(e.target)}})},{threshold:.06});cards.forEach(c=>io.observe(c))},150)}document.addEventListener("DOMContentLoaded",()=>{initReveal();initNav();initActiveLink();initMobileMenu();initCountUp();initScroll();initFooter();initProgress();initTypewriter();initParticles();initCursor();setTimeout(initCardReveal,200);setTimeout(initTilt,400)});